VALUES
  ('optician-moex-01879', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡鏡片反覆放入高壓滅菌器中，在100 kPa的壓力，加熱至121℃，120分鐘可達到滅菌效果。 下列何者較無法以此高溫高壓的方式達到滅菌效果？', '["細菌", "病毒", "真菌", "棘狀阿米巴原蟲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01880', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '黏稠劑（viscosity agents）中的何種成分可用來增加隱形眼鏡護理液的潤濕時間及舒適性？', '["甲基纖維素（methyl cellulose）", "氯化鈉（sodium chloride）", "乙二胺四乙酸（ethylenediaminetetraacetic acid, EDTA）", "苯甲醇（benzyl alcohol）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01881', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式鏡片清潔液（cleaning solution）不適合使用於軟式鏡片的原因，下列何者正確？', '["硬式鏡片清潔液有緩衝劑（buffering agent）", "硬式鏡片清潔液比軟式鏡片清潔藥水更有效，所以硬式鏡片清潔液進入軟式鏡片材料的機會較 大，引發毒性反應", "硬式鏡片清潔液有表面活性劑（surfactant）", "硬式鏡片清潔液有潤濕劑（wetting agent）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01882', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '當比較隱形眼鏡清潔系統的性能時，以下那一項在抗棘狀阿米巴原蟲效力最佳？', '["多功能藥水（multipurpose solutions）", "生理食鹽水", "潤濕液", "3%過氧化氫藥水（過夜浸泡）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01883', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關RGP鏡片保存液中常見的防腐劑，下列敘述何者正確？', '["RGP鏡片溶液中使用的防腐劑會比軟式溶液的防腐劑有較高的眼睛敏感反應", "若配戴者對硫柳汞（thimerosal）過敏，會出現紅眼及上皮點狀角膜炎的現象", "聚季銨鹽-1（polyquaternium-1）與苯扎氯銨（BAK）相比，會對眼睛產生較多的過敏反應", "苯甲醇具有高分子量、單極性、非水溶性的特性，是一種良好的消毒劑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01884', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡沉積物及保養相關敘述，何者正確？', '["表面活性劑可以去除蛋白質的沉積，但不能截斷脂質與鏡片的結合", "Jelly bumps為常見沉澱物之一，常發生於長戴式鏡片上且會影響視覺品質", "含有沉積物之鏡片會降低鏡片氧氣傳導率、滑動量及防腐劑之功效", "表面活性劑會與其他溶液發生化學反應，因此不能一起使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01885', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一個平常戴-5.00 DS鏡框眼鏡（頂點距離12 mm）矯正的近視眼20歲年輕人，若換戴軟式隱形眼鏡 時且要有相當的遠距離視力，最接近的隱型眼鏡度數為何？', '["-5.25 DS", "-4.50 DS", "-5.00 DS", "-4.75 DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01886', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在驗配軟式隱形眼鏡時，使用上推法（push-up test）測試鏡片的滑動度，下列那一個上推法狀況是 可以被接受的？', '["無法推動鏡片", "可以推動鏡片，上推動作結束後，鏡片位置維持不變", "可以推動鏡片，上推動作結束後，鏡片位置會自行回到原點", "可以推動鏡片，上推動作結束後，鏡片在眨眼後會回到原點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01887', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在鞏膜硬式隱形眼鏡的標準試戴時，希望維持的角膜頂尖淚液空間大約為下列何者？', '["50-100 μm", "100-250 μm", "250-500 μm", "> 600 μm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01888', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若某病患其右眼眼睛近視度數-3.00 D，散光度度數-1.00D@180，角膜弧度（keratometric readings） 為44.50D@090/43.50D@180，驗配RGP lens選擇中心基弧半徑（base curve radius, BCR）43.75 D， 則所需隱形眼鏡鏡片度數為何？', '["-2.75 DS", "-3.00 DS", "-3.25 DS", "-3.50 DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
